import{_ as i,o,c as t,ae as a}from"./chunks/framework.DQWLcdWU.js";const u=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),n={name:"guide/concepts.md"};function l(r,e,s,c,d,p){return o(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><p>Guess‑Rater is a <strong>flexible, open‑source fuzzy matching engine</strong>.</p><p>It is designed to be:</p><ul><li>easy to use</li><li>highly configurable</li><li>adaptable to many different use‑cases</li><li>extensible by the community</li></ul><hr><h2 id="the-matching-pipeline" tabindex="-1">The matching pipeline <a class="header-anchor" href="#the-matching-pipeline" aria-label="Permalink to &quot;The matching pipeline&quot;">​</a></h2><p>Guess‑Rater works as a <strong>pipeline</strong>.</p><p>Every comparison follows these steps:</p><ol><li><strong>Normalization</strong></li><li><strong>Algorithm comparison</strong></li><li><strong>Score computation</strong></li><li><strong>Threshold evaluation</strong></li><li><em>(optional)</em> Explain &amp; ranking</li></ol><p>Understanding this pipeline is the key to using the library correctly.</p><hr><h2 id="_1-normalization" tabindex="-1">1. Normalization <a class="header-anchor" href="#_1-normalization" aria-label="Permalink to &quot;1. Normalization&quot;">​</a></h2><p>Before comparing two strings, Guess‑Rater can normalize them.</p><p>Normalization reduces differences that usually do not matter, such as:</p><ul><li>accents (<code>Molière</code> → <code>Moliere</code>)</li><li>punctuation (<code>SAINT-MICHEL.</code> → <code>SAINT MICHEL</code>)</li><li>casing (<code>Paris</code> vs <code>paris</code>)</li><li>word order (<code>Tower Eiffel</code> vs <code>Eiffel Tower</code>)</li><li>noise or typos (<code>bartndr</code> → <code>bartender</code>)</li></ul><p>Normalization is controlled with <code>options.normalize</code>.</p><p>You decide what is important and what is not.</p><hr><h2 id="_2-algorithm-comparison" tabindex="-1">2. Algorithm comparison <a class="header-anchor" href="#_2-algorithm-comparison" aria-label="Permalink to &quot;2. Algorithm comparison&quot;">​</a></h2><p>After normalization, strings are compared using one algorithm:</p><ul><li><code>levenshtein</code></li><li><code>jaroWinkler</code></li><li><code>tokenSort</code></li><li><code>tokenSet</code></li><li><code>hybrid</code></li></ul><p>Each algorithm measures similarity differently.</p><p>There is <strong>no single “best” algorithm</strong>. The right choice depends entirely on your domain.</p><hr><h2 id="_3-score-computation" tabindex="-1">3. Score computation <a class="header-anchor" href="#_3-score-computation" aria-label="Permalink to &quot;3. Score computation&quot;">​</a></h2><p>The comparison produces a <strong>score between 0 and 100</strong>.</p><ul><li><code>0</code> means completely different</li><li><code>100</code> means identical after normalization</li></ul><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rate(&#39;Black Peugeot&#39;, &#39;Black Peugeot&#39;) → 100</span></span>
<span class="line"><span>rate(&#39;Black Peugeot&#39;, &#39;Peugeot&#39;) → lower score</span></span></code></pre></div><p>The score represents <strong>how close the information is</strong>, not how similar the formatting is.</p><hr><h2 id="_4-threshold-and-match" tabindex="-1">4. Threshold and match <a class="header-anchor" href="#_4-threshold-and-match" aria-label="Permalink to &quot;4. Threshold and match&quot;">​</a></h2><p>A <strong>threshold</strong> defines when two strings are considered a match.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>match = score &gt;= threshold</span></span></code></pre></div><ul><li>Default threshold: <code>80</code></li><li>Higher threshold → stricter matching</li><li>Lower threshold → more tolerant matching</li></ul><p>This is what <code>isMatch()</code> does internally.</p><hr><h2 id="_5-explain-mode" tabindex="-1">5. Explain mode <a class="header-anchor" href="#_5-explain-mode" aria-label="Permalink to &quot;5. Explain mode&quot;">​</a></h2><p>When <code>explain: true</code> is enabled, Guess‑Rater returns a detailed object:</p><ul><li>final score</li><li>match boolean</li><li>normalized strings</li><li>algorithm breakdown (for hybrid)</li></ul><p>Explain mode is meant for:</p><ul><li>debugging</li><li>tuning thresholds</li><li>understanding <em>why</em> something matches or not</li></ul><hr><h2 id="score-vs-match" tabindex="-1">Score vs Match <a class="header-anchor" href="#score-vs-match" aria-label="Permalink to &quot;Score vs Match&quot;">​</a></h2><p>Important distinction:</p><ul><li><strong>score</strong> is continuous (0–100)</li><li><strong>match</strong> is boolean (true / false)</li></ul><p>You should always tune your threshold based on your use‑case.</p><hr><h2 id="designed-to-be-generic" tabindex="-1">Designed to be generic <a class="header-anchor" href="#designed-to-be-generic" aria-label="Permalink to &quot;Designed to be generic&quot;">​</a></h2><p>Guess‑Rater does <strong>not</strong> enforce a specific domain.</p><p>It can be used for:</p><ul><li>person name matching</li><li>product title matching</li><li>fuzzy search</li><li>quiz answer validation</li><li>data cleaning and deduplication</li><li>tolerant user input validation</li></ul><p>And also for:</p><ul><li>custom business rules</li><li>experimental matching strategies</li><li>domain‑specific heuristics</li></ul><p>You decide how strict or tolerant it should be.</p><hr><h2 id="open‐source-contributions" tabindex="-1">Open‑source &amp; contributions <a class="header-anchor" href="#open‐source-contributions" aria-label="Permalink to &quot;Open‑source &amp; contributions&quot;">​</a></h2><p>Guess‑Rater is an <strong>open‑source project</strong>.</p><p>You are encouraged to:</p><ul><li>use it freely in your own projects</li><li>adapt it to your needs</li><li>experiment with new ideas</li><li>propose improvements</li></ul><p>Contributions are welcome, including:</p><ul><li>new algorithms</li><li>new normalization options</li><li>performance improvements</li><li>documentation improvements</li><li>new examples and recipes</li><li>bug fixes</li></ul><p>If something does not fit your use‑case, it is very likely intentional: the library is meant to be <strong>extended</strong>, not locked.</p><hr><h2 id="mental-model" tabindex="-1">Mental model <a class="header-anchor" href="#mental-model" aria-label="Permalink to &quot;Mental model&quot;">​</a></h2><p>Think of Guess‑Rater as:</p><blockquote><p>“Compare information content, not formatting.”</p></blockquote><p>Normalization removes noise.<br> Algorithms measure similarity.<br> Thresholds decide acceptance.</p><p>Everything else is up to you.</p>`,69)])])}const m=i(n,[["render",l]]);export{u as __pageData,m as default};
